#' @param label_size_list How the
#' label sizes are to be changed.
#' See 'Details' on
#' how to set this argument. If a list
#' of named list is used, the element
#' for new background color should be
#' named `new_label_size`.
#'
#' @examples
#'
#' # ==== set_edge_label_size ====
#'
#' my_label_size_vector <- c(
#'   "x3 ~ x2" = 2,
#'   "x4 ~ x1" = 3
#' )
#' p_pa5v <- set_edge_label_size(
#'              p_pa,
#'              my_label_size_vector
#'            )
#' plot(p_pa5v)
#'
#' # This approach is no longer recommended
#' my_label_size_list <- list(
#'                      list(
#'                        from = "x2",
#'                        to = "x3",
#'                        new_label_size = 2
#'                       ),
#'                      list(
#'                        from = "x1",
#'                        to = "x4",
#'                        new_label_size = 3)
#'                      )
#' p_pa5l <- set_edge_label_size(
#'              p_pa,
#'              my_label_size_list
#'            )
#' plot(p_pa5l)
#'
#'
#' @rdname set_edge_label_attributes
#' @export
set_edge_label_size <- function(
  semPaths_plot,
  label_size_list = NULL,
  how = c("ratio", "value"),
  check_direction = TRUE
) {

  how <- match.arg(how)

  # This version use set_edge_attribute()

  if (is.null(label_size_list)) {
    stop("label_size_list not specified.")
  }
  if (is.null(semPaths_plot)) {
    stop("semPaths_plot not specified.")
  }

  # Fix the names
  label_size_list_fixed <- to_new_value(
    label_size_list,
    original_name = "new_label_size"
  )
  out <- set_edge_attribute(semPaths_plot = semPaths_plot,
                            values = label_size_list_fixed,
                            attribute_name = "label.cex",
                            how = how,
                            check_direction = check_direction)

  out
}

#' @noRd
set_edge_label_position_old <- function(semPaths_plot, position_list = NULL) {
    # TODO:
    # - Update to use set_edge_attribute().
    if (is.null(position_list)) {
        stop("position_list not specified.")
      }
    if (is.null(semPaths_plot)) {
        stop("semPaths_plot not specified.")
      } else {
        if (!inherits(semPaths_plot, "qgraph")) {
            stop("semPaths_plot is not a qgraph object.")
          }
      }

    # Convert a named vector to a named list
    if (!is.list(position_list) && is.numeric(position_list)) {
        position_list_org <- position_list
        position_list <- to_list_of_lists(position_list,
                                       name1 = "from",
                                       name2 = "to",
                                       name3 = "new_position")
      }

    Nodes_names <- semPaths_plot$graphAttributes$Nodes$names
    Nodes_id <- seq_len(length(Nodes_names))
    names(Nodes_id) <- Nodes_names
    position_old <- semPaths_plot$graphAttributes$Edges$edge.label.position
    position_new <- position_old
    position_index <- sapply(position_list, function(x) {
          edge_index(semPaths_plot, from = x$from, to = x$to)
        })
    position_new[position_index] <- sapply(position_list, function(x) x$new_position)

    # Check bidirectional edges
    position_list2 <- position_list[which(semPaths_plot$Edge$bidirectional[position_index])]
    if (length(position_list2) > 0) {
      position_index2 <- sapply(position_list2, function(x) {
            edge_index(semPaths_plot, from = x$to, to = x$from)
         })
      position_new[position_index2] <- sapply(position_list2, function(x) x$new_position)
    }

    semPaths_plot$graphAttributes$Edges$edge.label.position <- position_new
    semPaths_plot
  }
